  1	import * as React from 'react';
  2	import { AccessKeyStatus } from '@odf/core/constants/s3-iam';
  3	import { useCustomTranslation } from '@odf/shared';
  4	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  5	import { IamCommands } from '@odf/shared/iam';
  6	import { CommonModalProps } from '@odf/shared/modals';
  7	import {
  8	  Button,
  9	  ButtonVariant,
 10	  Flex,
 11	  FlexItem,
 12	  Modal,
 13	  ModalVariant,
 14	} from '@patternfly/react-core';
 15	
 16	export type UpdateAccessKeyModalProps = {
 17	  name: string;
 18	  AccessKeyId: string;
 19	  updateStatusTo: AccessKeyStatus;
 20	  iamClient: IamCommands;
 21	  refreshTokens: () => void;
 22	};
 23	
 24	const UpdateAccessKeyModal: React.FC<
 25	  CommonModalProps<UpdateAccessKeyModalProps>
 26	> = ({
 27	  closeModal,
 28	  isOpen,
 29	  extraProps: { name, AccessKeyId, updateStatusTo, iamClient, refreshTokens },
 30	}) => {
 31	  const { t } = useCustomTranslation();
 32	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 33	  const [error, setError] = React.useState<Error>();
 34	
 35	  const handleClose = () => {
 36	    if (!inProgress) {
 37	      closeModal();
 38	    }
 39	  };
 40	
 41	  const handleSubmit = async (
 42	    event: React.MouseEvent<HTMLButtonElement>
 43	  ): Promise<void> => {
 44	    event.preventDefault();
 45	    setInProgress(true);
 46	    setError(undefined);
 47	
 48	    try {
 49	      await iamClient.updateAccessKey({
 50	        UserName: name,
 51	        AccessKeyId,
 52	        Status: updateStatusTo,
 53	      });
 54	      setInProgress(false);
 55	      closeModal();
 56	      refreshTokens?.();
 57	    } catch (err) {
 58	      setInProgress(false);
 59	      setError(err as Error);
 60	    }
 61	  };
 62	
 63	  const { title, descriptionText, buttonType, buttonText } =
 64	    React.useMemo(() => {
 65	      const isActivating = updateStatusTo === AccessKeyStatus.ACTIVE;
 66	      return {
 67	        title: t(
 68	          isActivating ? 'Activate access key' : 'Deactivate access key'
 69	        ),
 70	        descriptionText: t(
 71	          isActivating
 72	            ? 'Activated users can access policies and permissions. You can now assign or update access control for this user.'
 73	            : 'Deactivated users cannot access policies or permissions. You will need to reactivate the user to restore access control.'
 74	        ),
 75	        buttonType: isActivating ? ButtonVariant.primary : ButtonVariant.danger,
 76	        buttonText: t(isActivating ? 'Activate' : 'Deactivate'),
 77	      };
 78	    }, [updateStatusTo, t]);
 79	
 80	  return (
 81	    <Modal
 82	      variant={ModalVariant.medium}
 83	      isOpen={isOpen}
 84	      onClose={handleClose}
 85	      title={title}
 86	      description={<div className="text-muted">{descriptionText}</div>}
 87	      actions={[
 88	        <ButtonBar
 89	          className="pf-v6-u-w-100"
 90	          inProgress={inProgress}
 91	          errorMessage={error ? error?.message || JSON.stringify(error) : ''}
 92	        >
 93	          <Flex>
 94	            <FlexItem>
 95	              <Button
 96	                variant={buttonType}
 97	                onClick={handleSubmit}
 98	                isLoading={inProgress}
 99	                isDisabled={inProgress}
100	              >
101	                {buttonText}
102	              </Button>
103	            </FlexItem>
104	            <FlexItem>
105	              <Button
106	                variant={ButtonVariant.plain}
107	                onClick={closeModal}
108	                isDisabled={inProgress}
109	              >
110	                {t('Cancel')}
111	              </Button>
112	            </FlexItem>
113	          </Flex>
114	        </ButtonBar>,
115	      ]}
116	    >
117	      <Flex direction={{ default: 'column' }}>
118	        <FlexItem>
119	          <label className="pf-v6-u-font-weight-bold">{t('Access key')}</label>
120	        </FlexItem>
121	        <FlexItem>
122	          <div className="text-muted">{AccessKeyId}</div>
123	        </FlexItem>
124	      </Flex>
125	    </Modal>
126	  );
127	};
128	
129	export default UpdateAccessKeyModal;

